        o("interpolation", MpvOptionSection.Video, MpvOptionType.Boolean, "no", listOf("yes", "no"), "Interpolación de video.", "Opción oficial para activar interpolación cuando el modo de sincronización lo permite.", AndroidSupport.CompatibleAdvanced, "mpv-android la ofrece como ajuste avanzado; puede aumentar uso de GPU.", RiskLevel.Medium, "interpolation=yes", listOf("no", "yes"), MPV_ANDROID_PREFS),
