        o("deband", MpvOptionSection.Video, MpvOptionType.Boolean, "no", listOf("yes", "no"), "Reduce banding de color.", "Opción oficial de renderizado para aplicar debanding.", AndroidSupport.CompatibleAdvanced, "mpv-android lo expone; puede mejorar gradientes pero aumenta coste GPU.", RiskLevel.Medium, "deband=yes", listOf("no", "yes"), MPV_ANDROID_PREFS),
        o("deband-iterations", MpvOptionSection.Video, MpvOptionType.Integer, "1", emptyList(), "Iteraciones de debanding.", "mpv permite ajustar cuántas iteraciones aplica el filtro de debanding.", AndroidSupport.CompatibleAdvanced, "Más iteraciones implican más coste de GPU.", RiskLevel.Medium, "deband-iterations=2", listOf("1", "2"), MPV_MANUAL),
        o("deband-threshold", MpvOptionSection.Video, MpvOptionType.Number, null, emptyList(), "Umbral de debanding.", "Opción oficial para ajustar la sensibilidad del debanding.", AndroidSupport.CompatibleAdvanced, "Valores altos pueden eliminar detalle fino.", RiskLevel.Medium, "deband-threshold=35", listOf("35", "48"), MPV_MANUAL),
        o("deinterlace", MpvOptionSection.Video, MpvOptionType.Boolean, "no", listOf("yes", "no"), "Activa desentrelazado.", "mpv documenta esta opción para activar el filtro de desentrelazado cuando aplica.", AndroidSupport.CompatibleAdvanced, "Útil solo para contenido entrelazado; innecesario en video progresivo.", RiskLevel.Medium, "deinterlace=no", listOf("no", "yes"), MPV_MANUAL),
        o("framedrop", MpvOptionSection.Video, MpvOptionType.Choice, "vo", listOf("no", "vo", "decoder", "decoder+vo"), "Permite descartar frames.", "Opción oficial para mantener sincronía cuando el decodificado/renderizado no alcanza.", AndroidSupport.CompatibleAdvanced, "Puede ayudar en dispositivos lentos, pero reduce suavidad.", RiskLevel.Medium, "framedrop=vo", listOf("vo", "decoder"), MPV_MANUAL),
        o("speed", MpvOptionSection.Playback, MpvOptionType.Number, "1.0", emptyList(), "Velocidad de reproducción.", "mpv permite cambiar la velocidad de reproducción respecto a tiempo real.", AndroidSupport.RecommendedAndroid, "Seguro para presets de reproducción; valores extremos afectan audio y consumo.", RiskLevel.Low, "speed=1.25", listOf("1.0", "1.25", "1.5"), MPV_MANUAL),
        o("loop-file", MpvOptionSection.Playback, MpvOptionType.Choice, "no", listOf("no", "inf", "yes"), "Repite el archivo actual.", "Opción oficial para repetir el archivo una vez o indefinidamente.", AndroidSupport.CompatibleAdvanced, "Útil para pruebas o clips; puede confundir si queda activo globalmente.", RiskLevel.Low, "loop-file=inf", listOf("no", "inf"), MPV_MANUAL),
        o("save-position-on-quit", MpvOptionSection.Playback, MpvOptionType.Boolean, "no", listOf("yes", "no"), "Guarda posición al salir.", "mpv documenta esta opción para escribir estado de reproducción y poder reanudar.", AndroidSupport.RecommendedAndroid, "Útil en móvil; requiere que la app pueda escribir en su directorio de configuración/estado.", RiskLevel.Low, "save-position-on-quit=yes", listOf("yes", "no"), MPV_MANUAL),
