    val optionsByAndroidSupport: Map<AndroidSupport, List<MpvOption>> =
        androidRelevantOptions.groupBy { it.androidSupport }

    fun findByKey(key: String): MpvOption? = androidRelevantOptions.firstOrNull { it.key == key }

    private fun o(
        key: String,
        section: MpvOptionSection,
        type: MpvOptionType,
        defaultValue: String?,
        choices: List<String>,
        shortDescription: String,
        longDescription: String,
        androidSupport: AndroidSupport,
        androidNote: String,
        riskLevel: RiskLevel,
        example: String,
        recommendedValues: List<String>,
        sourceUrl: String,
    ) = MpvOption(
        key = key,
        section = section,
        type = type,
        defaultValue = defaultValue,
        choices = choices,
        shortDescription = shortDescription,
        longDescription = longDescription,
        androidSupport = androidSupport,
        androidNote = androidNote,
        riskLevel = riskLevel,
        sourceUrl = sourceUrl,
        sourceAnchor = "--$key",
        example = example,
        recommendedValues = recommendedValues,
    )
}
